const raw = $input.first().json.sql_command || '';
const tenant = $input.first().json.tenant_slug || 'demo';

function extraerSQL(input) {
  let s = input.trim();
  const mdMatch = s.match(/```(?:sql)?\s*([\s\S]*?)```/i);
  if (mdMatch) s = mdMatch[1].trim();
  const selectIdx = s.search(/\bSELECT\b/i);
  if (selectIdx > 0) s = s.slice(selectIdx);
  s = s.replace(/;\s*$/, '').trim();
  return s;
}

function validarSQL(query) {
  if (!query || query.trim().length === 0) return false;
  const cleaned = query.trim();
  // Word boundaries para evitar falsos positivos en columnas como created_at, inserted_by, etc.
  const prohibidos = /\bDROP\b|\bTRUNCATE\b|\bDELETE\b|\bUPDATE\b|\bALTER\b|\bINSERT\b|\bCREATE\b|\bGRANT\b|\bREVOKE\b|\bCOPY\b|information_schema|pg_catalog/i;
  if (prohibidos.test(cleaned)) return false;
  if (!/^SELECT\b/i.test(cleaned)) return false;
  return true;
}

function inyectarTenant(query, tenantSlug) {
  if (query.toLowerCase().includes('tenant_slug')) return query;
  const hasWhere = /\bWHERE\b/i.test(query);
  const orderMatch = query.match(/(ORDER\s+BY|LIMIT|OFFSET)/i);
  if (orderMatch) {
    const idx = query.toLowerCase().indexOf(orderMatch[0].toLowerCase());
    const before = query.slice(0, idx).trimEnd();
    const after = query.slice(idx);
    return hasWhere
      ? before + ` AND tenant_slug = '${tenantSlug}' ` + after
      : before + ` WHERE tenant_slug = '${tenantSlug}' ` + after;
  }
  return hasWhere
    ? query + ` AND tenant_slug = '${tenantSlug}'`
    : query + ` WHERE tenant_slug = '${tenantSlug}'`;
}

const sqlLimpio = extraerSQL(raw);
const esValida = validarSQL(sqlLimpio);
const sqlFinal = esValida ? inyectarTenant(sqlLimpio, tenant) : '';

return [{ json: {
  resultado: esValida ? 'SQL_VALIDO' : 'SQL_INVALIDO',
  sql_final: sqlFinal,
  sql_original: raw,
  tenant_slug: tenant
}}];

const records = $input.all().map(item => item.json);
const total = records.length;

if (total === 0) {
  return [{ json: {
    resultado: 'Sin registros que coincidan con los criterios. Es probable que no haya datos cargados en la BD para esos filtros.',
    total: 0,
    success: true
  }}];
}

return [{ json: {
  resultado: JSON.stringify(records, null, 2),
  total: total,
  success: true
}}];

